int a[105], dp[105][105][10005], mn[105][10005];
void solve(int CASE)
{
	int n; cin >> n;
	fa(i, 0, n)fa(j, 0, 100)fa(k, 0, 10000)dp[i][j][k] = INF;
	fa(i, 1, n)cin >> a[i];
	dp[0][0][0] = 0;
	int sum = 0;
	int ans = INF;
	fa(i, 1, n) {
		sum += a[i];
		fa(j, 0, 100)fa(k, 0, 10000) {
			if (j == 0)mn[j][k] = dp[i - 1][j][k];
			else mn[j][k] = min(dp[i - 1][j][k], mn[j - 1][k]);
		}
		fa(j, 0, 100) {
			fa(lastk, 0, 10000) {
				int k = j * j + lastk;
				if (k > 10000)break;
				dp[i][j][k] = min(dp[i][j][k], abs(k - sum) + mn[j][lastk]);
				if (k == sum and i == n)ans = min(ans, dp[i][j][k]); // 仅在此处算答案
			}
		}
	}
	if (ans >= INF)cout << -1 << endl;
	else cout << ans << endl;
	return;
}
